//recipient A combos
    if (incomeA == 0) { //when income is 0-20k, poverty is between 0-60+%
        povertyA = (random([0,1,2,3,4,5,6,7]));
    }
    if (incomeA == 1) { //when income is 20-40k, poverty is between 0-50%
        povertyA = (random([0,1,2,3,4]));
    }
    if (incomeA == 2) { //when income is 40-60k, poverty is between 0-40%
        povertyA = (random([0,1,2,3]));
    }
    if (incomeA == 3) { //when income is 60-80k, poverty is between 0-20%
        povertyA = (random([0,1]));
    }
    if (incomeA == 4) { //when income is 80-100k, poverty is between 0-20%
        povertyA = (random([0,1]));
    }
    if (incomeA == 5) { //when income is 100k+, poverty is between 0-20%
        povertyA = (random([0,1]));
    }
